import{_ as l,C as i,o as d,c as h,j as e,a as t,E as n,a3 as m}from"./chunks/framework.CVjg771q.js";const y=JSON.parse('{"title":"天隐子","description":"唐代司马承祯的修真入门短篇，以易简为宗，渐门五阶，由斋戒至神解。","frontmatter":{"title":"天隐子","description":"唐代司马承祯的修真入门短篇，以易简为宗，渐门五阶，由斋戒至神解。","category":"guide","aliases":["天隐子","tianyinzi"],"source":["天隐子","司马承祯"]},"headers":[],"relativePath":"daoism/daoist-classics/tianyinzi.md","filePath":"daoism/daoist-classics/tianyinzi.md","lastUpdated":1779783531000}'),c={name:"daoism/daoist-classics/tianyinzi.md"};function p(u,a,b,_,f,g){const r=i("DaoReadingPrelude"),o=i("DaoOriginalReading"),s=i("DaoKeywordCards");return d(),h("div",null,[a[0]||(a[0]=e("h1",{id:"天隐子",tabindex:"-1"},[t("天隐子 "),e("a",{class:"header-anchor",href:"#天隐子","aria-label":'Permalink to "天隐子"'},"​")],-1)),n(r,{title:"先看天隐如何以简入门",summary:"天隐子比坐忘论更短、更简、更贴近日常。它以「易简」为总纲，将修真之路拆为渐门五阶——斋戒、安处、存想、坐忘、神解——不是跳空谈玄，而是从日常生活能下手的地方开始。",points:[{label:"先立纲",text:"「易简」不是偷懒，而是顺应天地本然的路径。"},{label:"再拆阶",text:"渐门五阶从饮食起居到心念专注，层层递进。"},{label:"后归本",text:"终点「神解」不是神通，而是心与道自然合一。"}],hint:"若是第一次读天隐子，建议先抓住「易简」二字，再看渐门五阶的递进关系。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[t("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(o,{paragraphs:["「神仙」","人生时禀得灵气，精明通悟，学无滞塞，则谓之神。宅神于内，遗照于外，自然异于俗人，则谓之神仙。故神仙亦人也，在于修我灵气，勿为世俗所沦污。","「易简」","易曰：「天地之道，易简而已。」","凡学神仙，先知易简。苟言诸奇诡，涉于怪诞，则非学矣。","「渐门」","易有渐卦，为学亦有渐门。渐门有五：一曰斋戒，二曰安处，三曰存想，四曰坐忘，五曰神解。","「斋戒」","斋戒者，非蔬茹饮食而已。斋者，洁净之谓也；戒者，节慎之谓也。","饥即食，食勿令饱；渴即饮，饮勿令多。此所谓调中也。","「安处」","何谓安处？非华堂邃宇，重裀广榻之谓也。在乎南向而坐，东首而寝，阴阳适中，明暗相半。","屋无高则阳盛而明多，屋无卑则阴盛而暗多。","「存想」","存谓存我之神，想谓想我之身。","闭目即见自己之目，收心即见自己之心。心与目合，即是存想。","「坐忘」","坐忘者，因存而得忘也。行道而不见其行，有心而不见其心，是谓坐忘。","彼我两忘，了无所照，是谓坐忘。","「神解」","一斋戒，谓之信解；二安处，谓之闲解；三存想，谓之慧解；四坐忘，谓之定解。","四解通神，谓之神解。信定闲慧，四门通解，则神之为义，不行而至，不疾而速。"]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[t("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(s,{title:"字词释义",items:[{term:"禀",pinyin:["bǐng"],meaning:"禀受，天赋之意。禀得灵气即天生有灵明。"},{term:"邃",pinyin:["suì"],meaning:"深邃。华堂邃宇指华丽的深宅大院。"},{term:"裀",pinyin:["yīn"],meaning:"重裀，多层褥垫。非追求舒适的意思。"},{term:"榻",pinyin:["tà"],meaning:"广榻，宽大的床。"},{term:"蔬",pinyin:["shū"],meaning:"蔬茹，指菜食。斋戒非仅指吃素。"},{term:"沦",pinyin:["lún"],meaning:"沦污，沉沦玷污。"}]}),a[3]||(a[3]=m("",11))])}const P=l(c,[["render",p]]);export{y as __pageData,P as default};
